const jobId = $('generate jobID').first().json.jobId;

const parsed = {
  jobId: jobId,
  frameRate: 24,
  totalFrames: 240,
  objects: [
    {
      meshName: "Thickener",
      keyframes: [
        { frame: 0, position: [0, 0, 0], rotation: [0, 0, 0], interpolation: "LINEAR" },
        { frame: 96, position: [0, 0, 0], rotation: [0, 0, 0], interpolation: "LINEAR" },
        { frame: 240, position: [0, 0, 0], rotation: [0, 0, 360], interpolation: "LINEAR" }
      ],
      constraints: []
    }
  ],
  cameraPath: [
    { frame: 0, position: [10, -10, 5], lookAt: [0, 0, 0], fov: 50 },
    { frame: 96, position: [2, -2, 1.5], lookAt: [0, 0, 0], fov: 50 },
    { frame: 240, position: [2, -2, 1.5], lookAt: [0, 0, 0], fov: 50 }
  ],
  timingOffsets: {}
};

return [{ json: parsed }];

const response = $('groq call2').first().json;
let rawText = response.choices[0].message.content;
rawText = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error('Claude Call 2: JSON parse failed — ' + e.message + ' | Raw: ' + rawText.substring(0, 300));
}
return [{ json: parsed }];

const parsed = $('Parse Claude Call 2 Response').first().json;
const jobId = $('generate jobID').first().json.jobId;
const intermediatesDir = $('generate jobID').first().json.intermediatesDir;

const jsonString = JSON.stringify(parsed, null, 2);
const binary = Buffer.from(jsonString, 'utf8').toString('base64');

return [{
  json: {
    jobId,
    intermediatesDir,
    fileName: `${jobId}-simulation-execution.json`
  },
  binary: {
    data: {
      data: binary,
      mimeType: 'application/json',
      fileName: `${jobId}-simulation-execution.json`
    }
  }
}];

